from langchain.callbacks import StdOutCallbackHandler, BaseCallbackHandler

class ToolLoopDetector(BaseCallbackHandler):
    def __init__(self):
        self.tool_calls = {}
        self.max_calls = 3

    def on_tool_start(self, serialized, input_str, **kwargs):
        tool_name = serialized['name']
        self.tool_calls[tool_name] = self.tool_calls.get(tool_name, 0) + 1
        if self.tool_calls[tool_name] > self.max_calls:
            raise ValueError(f'Tool loop detected: {tool_name} called {self.tool_calls[tool_name]} times')

# Usage
agent_executor = AgentExecutor.from_agent_and_tools(agent=agent, tools=tools, callbacks=[ToolLoopDetector()])
